import React, { useState } from "react";
import { XMarkIcon } from "@heroicons/react/24/solid";
import FloatingInput from "../component/FloatingInput";

export default function UserRegister({ closeModal }) {
  const [formData, setFormData] = useState({
    username: "",
    name: "",
    email: "",
    password: "",
    confirmPassword: "",
  });

  const [errors, setErrors] = useState({});
  const [success, setSuccess] = useState("");

  const BASE_URL = "http://localhost:8086";

  // ---------------- HANDLE CHANGE ----------------
  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });

    setErrors({
      ...errors,
      [e.target.name]: "",
    });
  };

  // ---------------- VALIDATION (IMPROVED YOUR IDEA) ----------------
  const validate = () => {
    const err = {};

    if (!formData.username) err.username = "Username is required";
    if (!formData.name) err.name = "Full name is required";

    // 🔥 STRICT STUDENT EMAIL FORMAT
    if (!formData.email) {
      err.email = "Email is required";
    } else if (!/^[iI][tT]\d{8}@my\.sliit\.lk$/.test(formData.email)) {
      err.email = "Use ITXXXXXXXX@my.sliit.lk format";
    }

    if (!formData.password) {
      err.password = "Password is required";
    } else if (formData.password.length < 6) {
      err.password = "Minimum 6 characters required";
    }

    if (!formData.confirmPassword) {
      err.confirmPassword = "Confirm your password";
    } else if (formData.password !== formData.confirmPassword) {
      err.confirmPassword = "Passwords do not match";
    }

    return err;
  };

  // ---------------- SUBMIT ----------------
  const handleSubmit = async (e) => {
    e.preventDefault();

    setErrors({});
    setSuccess("");

    const validationErrors = validate();
    if (Object.keys(validationErrors).length > 0) {
      setErrors(validationErrors);
      return;
    }

    try {
      // 🔍 check email exists
      const emailRes = await fetch(
        `${BASE_URL}/user/check-email/${formData.email}`
      );

      const exists = await emailRes.json();

      if (!exists) {
        setErrors({ email: "Email already exists" });
        return;
      }

      // 🧠 CREATE USER (FORCED STUDENT ROLE)
      const response = await fetch(`${BASE_URL}/user`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          username: formData.username,
          name: formData.name,
          email: formData.email,
          password: formData.password,
          role: "Student", // 🔥 YOUR IDEA IMPLEMENTED
        }),
      });

      if (response.ok) {
        setSuccess("Student registered successfully 🎉");

        setFormData({
          username: "",
          name: "",
          email: "",
          password: "",
          confirmPassword: "",
        });

        setTimeout(() => {
          closeModal();
        }, 1200);
      } else {
        const err = await response.json();
        setErrors({ submit: err.message || "Registration failed" });
      }
    } catch (error) {
      setErrors({
        submit: "Server not responding. Please try again.",
      });
    }
  };

  // ---------------- UI ----------------
  return (
    <div className="fixed inset-0 flex items-center justify-center z-50">

      {/* BACKDROP */}
      <div
        className="absolute inset-0 bg-black/40 backdrop-blur-sm"
        onClick={closeModal}
      />

      {/* GLASS CARD (CENTER FIXED) */}
      <div className="relative w-[500px] p-8 rounded-2xl backdrop-blur-xl bg-white/20 border border-white/30 shadow-2xl">

        <button
          onClick={closeModal}
          className="absolute top-3 right-3 text-white hover:text-red-400"
        >
          <XMarkIcon className="w-6 h-6" />
        </button>

        <h2 className="text-2xl font-bold text-white text-center mb-6">
          Student Registration
        </h2>

        {success && <p className="text-green-300 text-center">{success}</p>}
        {errors.submit && <p className="text-red-300 text-center">{errors.submit}</p>}

        <form onSubmit={handleSubmit} className="space-y-4 mt-4">

          <FloatingInput name="username" label="Username" value={formData.username} onChange={handleChange} />
          <FloatingInput name="name" label="Full Name" value={formData.name} onChange={handleChange} />
          <FloatingInput name="email" label="SLIIT Email" value={formData.email} onChange={handleChange} />
          <FloatingInput name="password" type="password" label="Password" value={formData.password} onChange={handleChange} />
          <FloatingInput name="confirmPassword" type="password" label="Confirm Password" value={formData.confirmPassword} onChange={handleChange} />

          <button className="w-full py-2 rounded-lg bg-white/30 hover:bg-white/40 text-white font-semibold">
            Register
          </button>
        </form>
      </div>
    </div>
  );
}
